import { actor } from "rivetkit";
import { db } from "rivetkit/db";

export const sqliteRawActor = actor({
	db: db({
		onMigrate: async (db) => {
			await db.execute(`
				CREATE TABLE IF NOT EXISTS todos (
					id INTEGER PRIMARY KEY AUTOINCREMENT,
					title TEXT NOT NULL,
					completed INTEGER DEFAULT 0,
					created_at INTEGER NOT NULL
				)
			`);
		},
	}),
	actions: {
		addTodo: async (c, title: string) => {
			const createdAt = Date.now();
			await c.db.execute(
				"INSERT INTO todos (title, created_at) VALUES (?, ?)",
				title,
				createdAt,
			);
			return { title, createdAt };
		},
		getTodos: async (c) => {
			return await c.db.execute("SELECT * FROM todos ORDER BY created_at DESC");
		},
		toggleTodo: async (c, id: number) => {
			await c.db.execute(
				"UPDATE todos SET completed = NOT completed WHERE id = ?",
				id,
			);
			const rows = await c.db.execute("SELECT * FROM todos WHERE id = ?", id);
			return rows[0];
		},
		deleteTodo: async (c, id: number) => {
			await c.db.execute("DELETE FROM todos WHERE id = ?", id);
			return { deleted: id };
		},
	},
});
